def build_queen(row_idx,col_idx):
    N=len(row_idx); W=np.zeros((N,N))
    for i in range(N):
        for j in range(N):
            if i!=j and max(abs(row_idx[i]-row_idx[j]),abs(col_idx[i]-col_idx[j]))&lt;=1:
                W[i,j]=1
    rs=W.sum(axis=1,keepdims=True); rs[rs==0]=1; return W/rs, (W&gt;0).astype(float)

